def assign_round_robin(
    workers: list[dict],
    jobs: list[str],
    capacities: dict[str, int] | None = None,
) -> list[dict]:
    enabled = [worker["name"] for worker in workers if worker.get("enabled", True)]
    if not enabled:
        raise ValueError("at least one worker must be enabled")
    capacities = capacities or {}
    used = {name: 0 for name in enabled}
    assignments = []
    cursor = 0
    for job in jobs:
        chosen = _next_available(enabled, capacities, used, cursor)
        if chosen is None:
            break
        worker, cursor = chosen
        used[worker] += 1
        assignments.append({"job": job, "worker": worker})
    return assignments


def _next_available(enabled, capacities, used, cursor):
    for offset in range(len(enabled)):
        index = (cursor + offset) % len(enabled)
        worker = enabled[index]
        cap = capacities.get(worker)
        if cap is None or used[worker] < cap:
            return worker, (index + 1) % len(enabled)
    return None

